#include <stdio.h>

// Without typedef - requires 'struct' keyword everywhere
struct Point1 {
    int x;
    int y;
};

// With typedef - no 'struct' keyword needed
typedef struct {
    int x;
    int y;
} Point2;

int main() {
    // Declaration without typedef
    struct Point1 p1 = {10, 20};

    // Declaration with typedef (simpler)
    Point2 p2 = {30, 40};

    printf("Without typedef: (%d, %d)\n", p1.x, p1.y);
    printf("With typedef: (%d, %d)\n", p2.x, p2.y);

    return 0;
}

#include <stdio.h>

// Typedef for pointer type
typedef int* IntPtr;

// Typedef for constant pointer
typedef int* const ConstIntPtr;

// Typedef for pointer to constant
typedef const int* IntConstPtr;

int main() {
    int num = 100;
    IntPtr p1 = &num;      // Equivalent to: int* p1
    ConstIntPtr p2 = &num; // Constant pointer: int* const p2
    IntConstPtr p3 = &num; // Pointer to constant: const int* p3

    printf("Value through p1: %d\n", *p1);
    printf("Value through p2: %d\n", *p2);
    printf("Value through p3: %d\n", *p3);

    // p2 = &num; // Error: p2 is constant pointer
    // *p3 = 200; // Error: p3 points to const

    return 0;
}

#include <stdio.h>

// Typedef for function pointer - takes int, returns int
typedef int (*CompareFunc)(int, int);

// Typedef for callback function
typedef void (*Callback)(const char*);

// Sample comparison functions
int ascending(int a, int b) {
    return a - b;
}

int descending(int a, int b) {
    return b - a;
}

// Sample callback
void logger(const char* msg) {
    printf("LOG: %s\n", msg);
}

int main() {
    // Using typedef for function pointers
    CompareFunc cmp = ascending;
    Callback log = logger;

    printf("Comparison result (ascending): %d\n", cmp(5, 3));

    // Switch to different function
    cmp = descending;
    printf("Comparison result (descending): %d\n", cmp(5, 3));

    // Use callback
    log("Operation completed");

    return 0;
}

#include <stdio.h>
#include <stdlib.h>

// Typedef for self-referential structure (linked list node)
typedef struct Node {
    int data;
    struct Node* next;  // Must use 'struct Node*', not 'Node*'
} Node;

// Function to create a new node
Node* createNode(int value) {
    Node* newNode = (Node*)malloc(sizeof(Node));
    newNode->data = value;
    newNode->next = NULL;
    return newNode;
}

// Function to print list
void printList(Node* head) {
    while (head != NULL) {
        printf("%d -> ", head->data);
        head = head->next;
    }
    printf("NULL\n");
}

int main() {
    // Creating linked list: 10 -> 20 -> 30
    Node* head = createNode(10);
    head->next = createNode(20);
    head->next->next = createNode(30);

    printf("Linked List: ");
    printList(head);

    // Free memory
    free(head->next->next);
    free(head->next);
    free(head);

    return 0;
}
